import React, { useState, useEffect } from 'react';
import getSubject from '../../api/getSubject.api';
import '../../reusable.css'
import './Subject.css'

function Subject() {
    const [allSubject, setAllSubject] = useState([])
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        getAllSubject()
    }, []);

    // get all unit
    const getAllSubject = async () => {
        await getSubject(setAllSubject, setLoading)
    }

    if (loading) return (<div className='loading-container'><div className='d-flex justify-content-center'><span className="page-loader"></span></div></div>)

    return (
        <div className='subject-container'>
            <div className='new-subject d-flex align-items-center'>
                <span>+</span>
                <p>Add New Subject</p>
            </div>
            <div className='subject-cover d-flex'>
                {allSubject?.map(item => {
                    return (
                        <div>
                            <p>{item.subjectName}</p>
                            <button className='subject-delete'>delete</button>
                            <button className='subject-update'>update</button>
                        </div>
                    )
                })}
            </div>
        </div>
    )
}

export default Subject
